1451 inline CmpClass_match<LHS, RHS, CmpInst, CmpInst::Predicate>
1452 m_Cmp(CmpInst::Predicate &Pred, const LHS &L, const RHS &R) {
1453   return CmpClass_match<LHS, RHS, CmpInst, CmpInst::Predicate>(Pred, L, R);
1454 }
