1563 inline ThreeOps_match<Cond, constantint_match<L>, constantint_match<R>,
1564                       Instruction::Select>
1565 m_SelectCst(const Cond &C) {
1566   return m_Select(C, m_ConstantInt<L>(), m_ConstantInt<R>());
